import { useState, useEffect } from 'react';
import { useTheme, THEMES, THEME_KEYS } from '../contexts/ThemeContext';
import usePageTitle from '../hooks/usePageTitle';
import s from './AppearancePage.module.css';

const ACCENT_COLORS = [
  { name: 'Cyan', value: '#22d3ee' },
  { name: 'Purple', value: '#A78BFA' },
  { name: 'Green', value: '#22C55E' },
  { name: 'Amber', value: '#F59E0B' },
  { name: 'Blue', value: '#60A5FA' },
  { name: 'Pink', value: '#F778BA' },
];

const FONT_SIZES = [
  { key: 'small', label: 'Small', value: 12, desc: 'Compact data density' },
  { key: 'medium', label: 'Medium', value: 14, desc: 'Balanced readability' },
  { key: 'large', label: 'Large', value: 16, desc: 'Maximum clarity' },
];

const CHART_STYLES = [
  { key: 'candles', label: 'Candlestick', icon: '\u2581\u2583\u2585\u2587\u2585\u2583' },
  { key: 'bars', label: 'OHLC Bars', icon: '\u2502\u2500\u2502\u2500\u2502\u2500' },
  { key: 'line', label: 'Line Chart', icon: '\u2571\u2572\u2571\u2500\u2571\u2572' },
];

const LAYOUT_OPTIONS = [
  { key: 'grid', label: 'Grid', desc: 'Card-based dashboard layout' },
  { key: 'list', label: 'List', desc: 'Vertical single-column layout' },
];

const SIDEBAR_OPTIONS = [
  { key: 'left', label: 'Left' },
  { key: 'right', label: 'Right' },
];

/* ── localStorage persistence ─────────────────────────────────────────── */
const APPEARANCE_LS_KEY = 'aura_appearance_prefs';

function loadAppearancePrefs() {
  try {
    const raw = localStorage.getItem(APPEARANCE_LS_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch { return null; }
}

function saveAppearancePrefs(prefs) {
  try { localStorage.setItem(APPEARANCE_LS_KEY, JSON.stringify(prefs)); } catch {}
}

/* ── Mini preview ─────────────────────────────────────────────────────── */
